// -----   Default constructor   -------------------------------------------
ShipMCTrack::ShipMCTrack()
    : TObject(),
      fPdgCode(0),
      fMotherId(-1),
      fPx(0.),
      fPy(0.),
      fPz(0.),
      fM(-1.),
      fStartX(0.),
      fStartY(0.),
      fStartZ(0.),
      fStartT(0.),
      fW(1.),
      fProcID(44),
      fNPoints(0),
      fEventID(0),
      fTrackID(0) {}
// -------------------------------------------------------------------------

// -----   Standard constructor   ------------------------------------------
ShipMCTrack::ShipMCTrack(Int_t pdgCode, Int_t motherId, Double_t px,
                         Double_t py, Double_t pz, Double_t M, Double_t x,
                         Double_t y, Double_t z, Double_t t, Int_t nPoints,
                         Int_t eventID, Int_t trackID, Double_t w)
    : TObject(),

      fPdgCode(track.fPdgCode),
      fMotherId(track.fMotherId),
      fPx(track.fPx),
      fPy(track.fPy),
      fPz(track.fPz),
      fM(track.fM),
      fStartX(track.fStartX),
      fStartY(track.fStartY),
      fStartZ(track.fStartZ),
      fStartT(track.fStartT),
      fW(track.GetWeight()),
      fProcID(track.GetProcID()),
      fNPoints(track.fNPoints),
      fEventID(track.fEventID),
      fTrackID(track.fTrackID) {}
// -------------------------------------------------------------------------

// -----   Constructor from TParticle   ------------------------------------
ShipMCTrack::ShipMCTrack(TParticle* part)
    : TObject(),
      fPdgCode(part->GetPdgCode()),
      fMotherId(part->GetMother(0)),
      fPx(part->Px()),
      fPy(part->Py()),
      fPz(part->Pz()),
      fM([](const TParticle* p) {
        Double_t m2 = p->Energy() * p->Energy() - p->P() * p->P();
        if (m2 >= 0.) return TMath::Sqrt(m2);
        // Tiny negative: numerical noise for on-shell massless particle
        Double_t e2 = p->Energy() * p->Energy();
        if (-m2 < 1e-10 * e2) return 0.;
        // Genuinely spacelike (virtual photon): store negative mass (ROOT
        // convention)
        return -TMath::Sqrt(-m2);
      }(part)),
      fStartX(part->Vx()),
      fStartY(part->Vy()),
      fStartZ(part->Vz()),
      fStartT(part->T() * 1e09),
      fW(part->GetWeight()),

        if (-m2 < 1e-10 * e2) return 0.;
        // Genuinely spacelike (virtual photon): store negative mass (ROOT
        // convention)
        return -TMath::Sqrt(-m2);
      }(part)),
      fStartX(part->Vx()),
      fStartY(part->Vy()),
      fStartZ(part->Vz()),
      fStartT(part->T() * 1e09),
      fW(part->GetWeight()),
      fProcID(part->GetUniqueID()),
      fNPoints(0),
      fEventID(0),
      fTrackID(0) {}
// -------------------------------------------------------------------------

// -----   Destructor   ----------------------------------------------------
ShipMCTrack::~ShipMCTrack() {}
// -------------------------------------------------------------------------

// -----   Public method Print   -------------------------------------------
void ShipMCTrack::Print(Int_t trackId) const {
  LOG(debug) << "Track " << trackId << ", mother : " << fMotherId << ", Type "
             << fPdgCode << ", momentum (" << fPx << ", " << fPy << ", " << fPz
             << ") GeV";
  /* LOG(DEBUG2) << "       Ref " << GetNPoints(kREF)
               << ", TutDet " << GetNPoints(kTutDet)
               << ", Rutherford " << GetNPoints(kFairRutherford) ;
 */
}
// -------------------------------------------------------------------------
// -----   Public method GetEnergy   -----------------------------------------

Double_t ShipMCTrack::GetEnergy() const {
  if (fM < 0) {
    // older data, mass not made persistent
    Double_t mass = GetMass();
    return TMath::Sqrt(mass * mass + fPx * fPx + fPy * fPy + fPz * fPz);
  } else {
    return TMath::Sqrt(fM * fM + fPx * fPx + fPy * fPy + fPz * fPz);

// -------------------------------------------------------------------------
// -----   Public method GetEnergy   -----------------------------------------

Double_t ShipMCTrack::GetEnergy() const {
  if (fM < 0) {
    // older data, mass not made persistent
    Double_t mass = GetMass();
    return TMath::Sqrt(mass * mass + fPx * fPx + fPy * fPy + fPz * fPz);
  } else {
    return TMath::Sqrt(fM * fM + fPx * fPx + fPy * fPy + fPz * fPz);
  }
}
// -----   Public method GetMass   -----------------------------------------
Double_t ShipMCTrack::GetMass() const {
  if (fM < 0) {
    // older data, mass not made persistent
    if (TDatabasePDG::Instance()) {
      TParticlePDG* particle = TDatabasePDG::Instance()->GetParticle(fPdgCode);
      if (particle) {
        return particle->Mass();
      } else {
        return 0.;
      }
    }
  }
  return fM;
}
// -------------------------------------------------------------------------

// -----   Public method GetWeight   -------------------------------------
Double_t ShipMCTrack::GetWeight() const { return fW; }
// -------------------------------------------------------------------------

// -----   Public method GetRapidity   -------------------------------------
Double_t ShipMCTrack::GetRapidity() const {
  Double_t e = GetEnergy();
  Double_t y = 0.5 * TMath::Log((e + fPz) / (e - fPz));
  return y;
}
// -------------------------------------------------------------------------

Double_t ShipMCTrack::GetWeight() const { return fW; }
// -------------------------------------------------------------------------

// -----   Public method GetRapidity   -------------------------------------
Double_t ShipMCTrack::GetRapidity() const {
  Double_t e = GetEnergy();
  Double_t y = 0.5 * TMath::Log((e + fPz) / (e - fPz));
  return y;
}
