  ShipMCTrack* mother = fUseSTL
                            ? &(*MCTrack_vec)[motherId]
                            : dynamic_cast<ShipMCTrack*>(MCTrack->At(motherId));
  Int_t Pcode = TMath::Abs(mother->GetPdgCode());
  return (Pcode == 221 || Pcode == 223 || Pcode == 333 || Pcode == 113 ||
          Pcode == 331);
