               pdgCode, TVector3(p->Vx(), p->Vy(), p->Vz()),
               TVector3(p->Px(), p->Py(), p->Pz()));
        ShipStack* stack = dynamic_cast<ShipStack*>(gMC->GetStack());
        stack->AddPoint(kVETO);
      }
    }
  }
  if ((!fCylindricalPlane) && fzPos > 1E8) {
    gMC->StopTrack();
  }
  return kTRUE;
}

