// private method make support of magnet
TGeoVolume* ShipMagnet::MagnetSupport(Double_t hwidth, Double_t hheight,
                                      Double_t dz, Int_t colour,
                                      TGeoMedium* material) {
  [[maybe_unused]] TGeoBBox* ms = new TGeoBBox("ms", hwidth, hheight - 1., dz);
  // try to make SHiP like logo in support
  Double_t swidth = 30.;  //
  // 6 cutouts from the front
  Double_t r25 = hheight - swidth / 2.;
  Double_t r1346 = hwidth - swidth / 2;
  Double_t alpha = atan(hheight / hwidth) * 180. / TMath::Pi();
  [[maybe_unused]] TGeoTubeSeg* FL1 =
      new TGeoTubeSeg("FL1", swidth, r1346, dz + 1., 5., alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* FL3 =
      new TGeoTubeSeg("FL3", swidth, r1346, dz + 1., 180 - alpha + 5., 175.);
  [[maybe_unused]] TGeoTubeSeg* FL4 =
      new TGeoTubeSeg("FL4", swidth, r1346, dz + 1., 185., 180. + alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* FL6 =
      new TGeoTubeSeg("FL6", swidth, r1346, dz + 1., 360. - alpha + 5., 355.);
  [[maybe_unused]] TGeoTubeSeg* FL2 = new TGeoTubeSeg(
      "FL2", swidth, r25, dz + 1., alpha + 5., 180 - alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* FL5 = new TGeoTubeSeg(
      "FL5", swidth, r25, dz + 1., 180. + alpha + 5., 360. - alpha - 5.);

  [[maybe_unused]] TGeoTubeSeg* FL3 =
      new TGeoTubeSeg("FL3", swidth, r1346, dz + 1., 180 - alpha + 5., 175.);
  [[maybe_unused]] TGeoTubeSeg* FL4 =
      new TGeoTubeSeg("FL4", swidth, r1346, dz + 1., 185., 180. + alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* FL6 =
      new TGeoTubeSeg("FL6", swidth, r1346, dz + 1., 360. - alpha + 5., 355.);
  [[maybe_unused]] TGeoTubeSeg* FL2 = new TGeoTubeSeg(
      "FL2", swidth, r25, dz + 1., alpha + 5., 180 - alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* FL5 = new TGeoTubeSeg(
      "FL5", swidth, r25, dz + 1., 180. + alpha + 5., 360. - alpha - 5.);

  // 6 cutouts from the side
  r1346 = dz - swidth / 2;
  alpha = atan(hheight / dz) * 180. / TMath::Pi();
  // cout << "magsupport: "<< swidth<<", "<<r25<<", "<< r1346<<", "<<alpha
  // <<endl;
  [[maybe_unused]] TGeoTubeSeg* SL1 =
      new TGeoTubeSeg("SL1", swidth, r1346, hwidth + 1., 5., alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* SL3 = new TGeoTubeSeg(
      "SL3", swidth, r1346, hwidth + 1., 180 - alpha + 5., 175.);
  [[maybe_unused]] TGeoTubeSeg* SL4 = new TGeoTubeSeg(
      "SL4", swidth, r1346, hwidth + 1., 185., 180. + alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* SL6 = new TGeoTubeSeg(
      "SL6", swidth, r1346, hwidth + 1., 360. - alpha + 5., 355.);
  [[maybe_unused]] TGeoTubeSeg* SL2 = new TGeoTubeSeg(
      "SL2", swidth, r25, hwidth + 1., alpha + 5., 180 - alpha - 5.);
  [[maybe_unused]] TGeoTubeSeg* SL5 = new TGeoTubeSeg(
      "SL5", swidth, r25, hwidth + 1., 180. + alpha + 5., 360. - alpha - 5.);
  TGeoRotation* r = new TGeoRotation("r");
  r->RotateY(90.);
  r->RegisterYourself();

  TGeoCompositeShape* TS = new TGeoCompositeShape(
      "TS", "ms-FL1-FL2-FL3-FL4-FL5-FL6-SL1:r-SL2:r-SL3:r-SL4:r-SL5:r-SL6:r");

  TGeoVolume* T = new TGeoVolume("TSUP", TS, material);
  T->SetLineColor(colour);
  return T;
}
