    [[maybe_unused]] TGeoTubeSeg* magnet1b =
        new TGeoTubeSeg("magnet1b", 250, 300, 35, 45, 135);
    [[maybe_unused]] TGeoTubeSeg* magnet1c =

  magyoke->SetLineColor(kBlue);
  // magyoke->SetTransparency(50);
  tMagnet->AddNode(magyoke, 1, new TGeoTranslation(0, 0, 1940));

  // magnet
  [[maybe_unused]] TGeoTubeSeg* magnet1a =
      new TGeoTubeSeg("magnet1a", 250, 300, 35, 45, 135);
  [[maybe_unused]] TGeoTubeSeg* magnet1b =
      new TGeoTubeSeg("magnet1b", 250, 300, 35, 45, 135);
