}

int veto::makeId(double z, double x, double y) {
  double Z = z / 10;
  double r = sqrt(x * x + y * y);
  double phi = 999;
  if (y >= 0)
    phi = acos(x / r);
  else
    phi = -acos(x / r) + 2 * TMath::Pi();

  phi = phi * 180 / TMath::Pi();
  return static_cast<int>(Z) * 1000000 + static_cast<int>(r) * 1000 +
         static_cast<int>(phi);
}

