  const std::string filename = std::string("test_") + sanitised_name + ".root";
  const std::string ntuple_name = std::string(class_name) + "_ntuple";

  try {
    // === WRITE TEST ===
    {
      auto model = RNTupleModel::Create();
      auto vec_field = model->MakeField<std::vector<T>>(class_name);

      auto writer =
          RNTupleWriter::Recreate(std::move(model), ntuple_name, filename);

      // Write test data
      *vec_field = test_objects;

